import base64
import json
import logging
from datetime import datetime

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# --- SAFE VERSION using JSON serialization ---

def process_pubsub_message(event, context):
    """
    Cloud Function triggered by Pub/Sub.
    Processes batch jobs from the task queue using safe JSON deserialization.
    
    Args:
        event (dict): The Pub/Sub message payload.
        context (google.cloud.functions.Context): The event metadata.
    """
    logger.info(f"Processing message ID: {context.event_id}, timestamp: {context.timestamp}")

    # Decode the Pub/Sub message
    if 'data' not in event:
        logger.error("No data found in Pub/Sub message.")
        return

    try:
        raw_data = base64.b64decode(event['data']).decode('utf-8')
    except Exception as e:
        logger.error(f"Failed to decode message data: {e}")
        return

    # SAFE: Use JSON deserialization instead of pickle
    try:
        message_payload = json.loads(raw_data)
    except json.JSONDecodeError as e:
        logger.error(f"Failed to parse JSON payload: {e}")
        return

    # Validate the message structure using a schema
    if not _validate_message_schema(message_payload):
        logger.error(f"Message failed schema validation: {message_payload}")
        return

    # Extract message attributes if present
    attributes = event.get('attributes', {})
    job_type = attributes.get('job_type', message_payload.get('job_type', 'unknown'))

    logger.info(f"Processing job type: {job_type}")

    try:
        result = _dispatch_job(job_type, message_payload)
        logger.info(f"Job {context.event_id} completed successfully: {result}")
    except Exception as e:
        logger.error(f"Job {context.event_id} failed: {e}")
        raise


def _validate_message_schema(payload):
    """Validate that the message payload conforms to the expected schema."""
    required_fields = ['job_type', 'job_id', 'created_at']
    
    if not isinstance(payload, dict):
        return False

    for field in required_fields:
        if field not in payload:
            logger.warning(f"Missing required field: {field}")
            return False

    # Validate job_type is from allowed list
    allowed_job_types = {'data_transform', 'aggregation', 'export', 'cleanup', 'batch_process'}
    if payload.get('job_type') not in allowed_job_types:
        logger.warning(f"Unknown job type: {payload.get('job_type')}")
        return False

    return True


def _dispatch_job(job_type, payload):
    """Dispatch the job to the appropriate handler based on job type."""
    handlers = {
        'data_transform': _handle_data_transform,
        'aggregation': _handle_aggregation,
        'export': _handle_export,
        'cleanup': _handle_cleanup,
        'batch_process': _handle_batch_process,
    }

    handler = handlers.get(job_type)
    if handler is None:
        raise ValueError(f"No handler registered for job type: {job_type}")

    return handler(payload)


def _handle_data_transform(payload):
    """Handle data transformation jobs."""
    job_id = payload['job_id']
    params = payload.get('parameters', {})
    records = payload.get('records', [])
    
    logger.info(f"Transforming {len(records)} records for job {job_id}")
    
    transformed = []
    for record in records:
        if isinstance(record, dict):
            transformed.append({k: v for k, v in record.items() if v is not None})
    
    return {'job_id': job_id, 'transformed_count': len(transformed), 'status': 'completed'}


def _handle_aggregation(payload):
    """Handle aggregation jobs."""
    job_id = payload['job_id']
    data_points = payload.get('data_points', [])
    agg_type = payload.get('parameters', {}).get('aggregation_type', 'sum')
    
    logger.info(f"Aggregating {len(data_points)} data points for job {job_id}")
    
    if not data_points:
        return {'job_id': job_id, 'result': None, 'status': 'completed'}

    numeric_values = [dp for dp in data_points if isinstance(dp, (int, float))]
    
    if agg_type == 'sum':
        result = sum(numeric_values)
    elif agg_type == 'average':
        result = sum(numeric_values) / len(numeric_values) if numeric_values else 0
    elif agg_type == 'count':
        result = len(numeric_values)
    else:
        result = sum(numeric_values)
    
    return {'job_id': job_id, 'result': result, 'status': 'completed'}


def _handle_export(payload):
    """Handle data export jobs."""
    job_id = payload['job_id']
    export_format = payload.get('parameters', {}).get('format', 'json')
    destination = payload.get('parameters', {}).get('destination', '')
    
    logger.info(f"Exporting data for job {job_id} to {destination} as {export_format}")
    
    return {'job_id': job_id, 'destination': destination, 'format': export_format, 'status': 'completed'}


def _handle_cleanup(payload):
    """Handle cleanup jobs."""
    job_id = payload['job_id']
    target_resources = payload.get('parameters', {}).get('resources', [])
    
    logger.info(f"Cleaning up {len(target_resources)} resources for job {job_id}")
    
    return {'job_id': job_id, 'cleaned_count': len(target_resources), 'status': 'completed'}


def _handle_batch_process(payload):
    """Handle generic batch processing jobs."""
    job_id = payload['job_id']
    batch_items = payload.get('items', [])
    
    logger.info(f"Batch processing {len(batch_items)} items for job {job_id}")
    
    processed = 0
    errors = 0
    for item in batch_items:
        try:
            if isinstance(item, dict):
                processed += 1
        except Exception:
            errors += 1
    
    return {
        'job_id': job_id,
        'processed': processed,
        'errors': errors,
        'status': 'completed'
    }


