def example_publish_job():
    """Example showing how to publish a job (for reference, not part of the Cloud Function)."""
    from google.cloud import pubsub_v1
    
    publisher = pubsub_v1.PublisherClient()
    topic_path = publisher.topic_path('my-project', 'task-queue')
    
    # Use JSON - safe and interoperable
    job = {
        'job_type': 'data_transform',
        'job_id': 'job-12345',
        'created_at': datetime.utcnow().isoformat(),
        'parameters': {'normalize': True, 'output_format': 'csv'},
        'records': [
            {'id': 1, 'name': 'Alice', 'value': 42.0},
            {'id': 2, 'name': 'Bob', 'value': None},
        ]
    }
    
    data = json.dumps(job).encode('utf-8')
    future = publisher.publish(topic_path, data, job_type='data_transform')
    print(f"Published message ID: {future.result()}")